class Solution {
public:
    string smallestEquivalentString(string s1, string s2, string baseStr) {
        int n = s1.size();
        vector<vector<char>> graph(26, vector<char>(26, '#'));
        for (int i = 0; i < n; i++) {
            graph[s1[i] - 'a'][s2[i] - 'a'] = '#';
            graph[s2[i] - 'a'][s1[i] - 'a'] = '#';
        }
        string res;
        for (char c : baseStr) {
            int x = c - 'a';
            while (graph[x][x] == '#') {
                for (int i = 0; i < 26; i++) {
                    if (graph[i][x] != '#') {
                        x = i;
                        break;
                    }
                }
            }
            res += x + 'a';
        }
        return res;
    }
};
```
